#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int* A = (int*) malloc(N * sizeof(int));
        int* B = (int*) malloc(N * sizeof(int));
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        int Pr = 0;
        for (int i = 0; i < N; i++) {
            if (A[i] == B[i]) {
                Pr++;
            }
        }
        while (Q--) {
            int x, y, z;
            scanf("%d %d %d", &x, &y, &z);
            int l = x ^ Pr;
            int r = y ^ Pr;
            int c = z ^ Pr;
            for (int i = l - 1; i < r; i++) {
                A[i] = c;
            }
            Pr = 0;
            for (int i = 0; i < N; i++) {
                if (A[i] == B[i]) {
                    Pr++;
                }
            }
            printf("%d\n", Pr);
        }
        free(A);
        free(B);
    }
    return 0;
}

